interface ByDate {
  date: Date,
  line: string, // of rgb
}
type rgb = "r" | "g" | "b"
interface Log {
  dates: ByDate[],
  counts: Record<rgb, number>
}

function parseDate(s: string): Date {
  const [y, m, d] = s.split("/").map(Number);
  return new Date(y, m - 1, d);
}

function formatDate(date: Date): string {
  const y = date.getFullYear();
  const m = String(date.getMonth() + 1).padStart(2, "0");
  const d = String(date.getDate()).padStart(2, "0");
  return `${y}/${m}/${d}`;
}

function todayKey(): string {
  return formatDate(new Date());
}

function rebuildCounts(dates: ByDate[]): Record<rgb, number> {
  const counts: Record<rgb, number> = { r: 0, g: 0, b: 0 };
  for (const { line } of dates) {
    for (const ch of line) {
      if (ch === "r" || ch === "g" || ch === "b") counts[ch]++;
    }
  }
  return counts;
}

function readLog(src: string): Log {
  /*
  src format
  2026/03/28 rb
  2026/03/30 g
  2026/03/31 r
  2026/04/01 rg
  2026/04/02 bb
  2026/04/03 r
  */
  const dates: ByDate[] = src
    .split("\n")
    .map(l => l.trim())
    .filter(l => l.length > 0)
    .map(l => {
      const [dateStr, line = ""] = l.split(" ");
      return { date: parseDate(dateStr), line };
    });

  return { dates, counts: rebuildCounts(dates) };
}

function writeLog(log: Log): string {
  return log.dates
    .map(({ date, line }) => `${formatDate(date)} ${line}`)
    .join("\n");
}

function addm(log: Log, e: rgb): void {
  // date is current time, if exists append to it
  const key = todayKey();
  const existing = log.dates.find(d => formatDate(d.date) === key);
  if (existing) {
    existing.line += e;
  } else {
    log.dates.push({ date: new Date(), line: e });
  }
  log.counts[e]++;
}
function add(log: Log, e: rgb): Log {
  return produce(log,(d)=>addm(d,e))
}
