/**
 * Chi-squared goodness-of-fit test for uniform rgb distribution.
 * H0: r, g, b counts are equally distributed.
 * Returns p-value. Small p => biased.
 */
function chiSquareBias(log: Log): number {
  const vals = [log.counts.r, log.counts.g, log.counts.b];
  const total = vals.reduce((a, b) => a + b, 0);
  if (total === 0) return 1;

  const expected = total / 3;
  const chi2 = vals.reduce((a, b) => a + (b - expected) ** 2 / expected, 0);
  const df = 2; // k-1 = 3-1

  return pValueFromChi2(chi2, df);
}

/** p-value from chi-squared distribution (upper tail) */
function pValueFromChi2(chi2: number, df: number): number {
  // P(X > chi2) = 1 - regularizedGammaP(df/2, chi2/2)
  return 1 - regularizedGammaP(df / 2, chi2 / 2);
}

/** Regularized lower incomplete gamma P(a, x) */
function regularizedGammaP(a: number, x: number): number {
  if (x < 0) return 0;
  if (x === 0) return 0;
  if (x < a + 1) return gammaSeries(a, x);
  return 1 - gammaCF(a, x);
}

function gammaSeries(a: number, x: number): number {
  const maxIter = 200, eps = 3e-7;
  let ap = a, sum = 1 / a, del = sum;
  for (let i = 0; i < maxIter; i++) {
    ap++;
    del *= x / ap;
    sum += del;
    if (Math.abs(del) < Math.abs(sum) * eps) break;
  }
  return sum * Math.exp(-x + a * Math.log(x) - lgamma(a));
}

function gammaCF(a: number, x: number): number {
  const maxIter = 200, eps = 3e-7;
  let b = x + 1 - a, c = 1 / 1e-30, d = 1 / b, h = d;
  for (let i = 1; i <= maxIter; i++) {
    const an = -i * (i - a);
    b += 2;
    d = an * d + b; if (Math.abs(d) < 1e-30) d = 1e-30;
    c = b + an / c; if (Math.abs(c) < 1e-30) c = 1e-30;
    d = 1 / d;
    const del = d * c;
    h *= del;
    if (Math.abs(del - 1) < eps) break;
  }
  return Math.exp(-x + a * Math.log(x) - lgamma(a)) * h;
}

function lgamma(x: number): number {
  // Stirling approximation
  const c = [76.18009172947146,-86.50532032941677,24.01409824083091,
              -1.231739572450155,0.1208650973866179e-2,-0.5395239384953e-5];
  let y = x, tmp = x + 5.5;
  tmp -= (x + 0.5) * Math.log(tmp);
  let ser = 1.000000000190015;
  for (const ci of c) ser += ci / ++y;
  return -tmp + Math.log(2.5066282746310005 * ser / x);
}